import { Component, OnInit } from "@angular/core";
import { DatePipe, formatNumber } from "@angular/common";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { HttpClient } from "@angular/common/http";
import { EnvService } from "src/app/core/services/env.service";
import { AlertService } from "src/app/core/services/alert.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import { ILoanUsage } from "src/app/views/Models/References/LoanUsage";

@Component({
  selector: "app-c",
  templateUrl: "./loan-usage.page.html",
  styleUrls: ["./loan-usage.page.scss"],
})
export class LoanUsagePage implements OnInit {
  [x: string]: any;
  loanUsageForm: any;
  LoanUsageRefTypes: StaticRef[];
  LoanUsageForm: FormGroup = this.formBuilder.group({
    loan_usage_code: [""],
    loan_usage_desc: ["", [Validators.required]],
    ref_code: ["", [Validators.required]],
  });
  noWhitespaceValidator(control: FormControl) {
    const isWhitespace =
      control.value !== null &&
      (control.value || "").toString().trim().length === 0;
    const isValid = !isWhitespace;
    return isValid ? null : { whitespace: true };
  }
  constructor(
    private formBuilder: FormBuilder,
    private datepipe: DatePipe,
    private http: HttpClient,
    private env: EnvService,
    private alertServices: AlertService,
    private ReferencesService: ReferencesService
  ) {}
  showLoader: boolean = false;
  LoanUsage: ILoanUsage[];
  isSubmitted: boolean = false;
  isInserting: boolean = false;
  isUpdating: boolean = false;

  ngOnInit() {
    this.loadLoanUsage();
  }
  async loadLoanUsage() {
    this.LoanUsage = await this.ReferencesService.getAllLoanUsage();
    this.LoanUsageRefTypes = await this.ReferencesService.GetAllLoanUsageRef();
  }
  updateLoanUsage(index: number) {
    const LoanUsage = this.LoanUsage[index];
    this.LoanUsageForm.patchValue({
      loan_usage_code: LoanUsage.loan_usage_code,
      loan_usage_desc: LoanUsage.loan_usage_desc,
      ref_code: Number(LoanUsage.usage_ref_code),
    });
    this.isInserting = false;
    this.isUpdating = true;
  }
  async insertLoanUsage() {
    this.isUpdating = false;
    this.isInserting = true;
  }
  async deleteLoanUsage(loan_usage_code: string) {
    if (await this.alertServices.SaveAlert("هل تريد الحذف؟"))
      await this.ReferencesService.GetLoanUsageDelete(
        loan_usage_code.toString()
      )
        .then(() => {
          this.alertServices.showAlertConfirm("تم الحذف بنجاح", true);
        })
        .catch((err) => {
          this.alertServices.showAlertError("لا يمكن حذف هذا الاستخدام", false);
        });
  }
  LoanUsageRef() {}
  clearForms() {
    this.isInserting = false;
    this.isUpdating = false;
    this.isSubmitted = false;
    this.LoanUsageForm.reset();
  }
  async submitLoanUsageInsert() {
    try {
      if (this.LoanUsageForm.valid) {
        if (await this.alertServices.SaveAlert("هل تريد الاضافة؟"))
          await this.ReferencesService.GetLoanUsageInsert(
            this.LoanUsageForm.value.loan_usage_desc,
            this.LoanUsageForm.value.ref_code
          ).then(() => {
            this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
          });
      } else {
        this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
      }
    } catch {}
  }
  async submitLoanUsageUpdate() {
    try {
      if (this.LoanUsageForm.valid) {
        if (await this.alertServices.SaveAlert("هل تريد تعديل البيانات؟"))
          await this.ReferencesService.GetLoanUsageUpdate(
            Number(this.LoanUsageForm.value.loan_usage_code),
            this.LoanUsageForm.value.loan_usage_desc,
            this.LoanUsageForm.value.ref_code
          ).then(() => {
            this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
          });
      } else {
        this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
      }
    } catch {}
  }
}
